const getAQIColor = (level) => {
/**
 * 获取等级数据
 * level：aqi等级值，1-6，无数据为7
 */
switch (level) {
  case '1':
  case 1:
    return '#00E400';
  case '2':
  case 2:
    return '#FFFF00';
  case '3':
  case 3:
    return '#FF7E00';
  case '4':
  case 4:
    return '#FF0000';
  case '5':
  case 5:
    return '#99004C';
  case '6':
  case 6:
    return '#7E0023';
  case '7':
  case 7:
    return '#AAAAAA';
  default:
    return '#AAAAAA';
}
};
